#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
mt19937 rnd(time(0));typedef long long ll;
const int N=3e5+10;int n,a[N],ql[N],qr[N],qk[N],qi[N],qx[N],Q,P[N<<1],p,A[N];
bool ans[N];ll h[N<<1],t[N];int cqt;
inline int bnd(int x){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=x?l=m+1:r=m-1;return l-1;}
inline void add(int x,ll w){while(x<=n)t[x]+=w,x+=(x&-x);}
inline ll qry(int l,int r)
{
	--l;ll res=0;while(r)res+=t[r],r^=(r&-r);
	while(l)res-=t[l],l^=(l&-l);return res;
}
inline void Solve()
{
	memset(t,0,sizeof(t));rep(1,p,i)h[i]=rnd()>>1;
	memcpy(A,a,sizeof(a));rep(1,n,i)add(i,h[A[i]]);
	rep(1,Q,i)
	{
		if(qi[i]){add(qi[i],h[qx[i]]-h[A[qi[i]]]);A[qi[i]]=qx[i];}
		else {ans[i]&=(qry(ql[i],qr[i])%qk[i]==0);}
	}
}
int main()
{
	n=read();Q=read();rep(1,n,i)P[++p]=a[i]=read();
	rep(1,Q,i)
	{
		if(read()==1)qi[i]=read(),P[++p]=qx[i]=read();
		else ql[i]=read(),qr[i]=read(),qk[i]=read();
	}
	sort(P+1,P+p+1);p=unique(P+1,P+p+1)-P-1;
	rep(1,n,i)a[i]=bnd(a[i]);rep(1,Q,i)if(qi[i])qx[i]=bnd(qx[i]);	
	memset(ans,1,sizeof(ans));int T=30;while(T--)Solve();
	rep(1,Q,i)if(!qi[i])puts(ans[i]?"YES":"NO");
}
